// Homepage — Server Component
// Greeting is in a separate client component so it reads YOUR browser timezone
import { createClient } from '@/lib/supabase/server'
import Link from 'next/link'
import type { ProjectWithRelations, AssignmentWithProfile } from '@/lib/types/database'
import Greeting from '@/components/ui/greeting'

export const metadata = { title: 'Home · Forge' }

// ─── ACTION CARD ───────────────────────────────────────────────────────────
function ActionCard({ icon, title, desc, href, accent = false }: {
  icon: string; title: string; desc: string; href: string; accent?: boolean
}) {
  return (
    <Link href={href} className="feature-card-hover" style={{
      background: accent ? 'var(--accent-light)' : 'var(--bg-surface)',
      border: `1px solid ${accent ? 'rgba(201,151,58,0.3)' : 'var(--border-subtle)'}`,
      borderRadius: 16, padding: '28px 24px',
      display: 'flex', flexDirection: 'column', gap: 14,
      textDecoration: 'none', minHeight: 160,
    }}>
      <div style={{
        width: 52, height: 52, borderRadius: 14,
        background: accent ? 'rgba(201,151,58,0.15)' : 'var(--bg-overlay)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 24,
        border: `1px solid ${accent ? 'rgba(201,151,58,0.2)' : 'var(--border-subtle)'}`,
      }}>
        {icon}
      </div>
      <div>
        <div style={{
          fontSize: 15, fontWeight: 600, marginBottom: 6,
          color: accent ? 'var(--accent)' : 'var(--text-primary)',
        }}>
          {title}
        </div>
        <div style={{ fontSize: 13, color: 'var(--text-muted)', lineHeight: 1.6 }}>
          {desc}
        </div>
      </div>
    </Link>
  )
}

// ─── TRENDING PROJECT CARD ─────────────────────────────────────────────────
function TrendingCard({ project }: { project: ProjectWithRelations }) {
  const tags   = project.project_tags?.map(pt => pt.tags).filter(Boolean) ?? []
  const author = project.profiles

  return (
    <Link href={`/projects/${project.id}`} className="project-card-hover" style={{
      background: 'var(--bg-surface)',
      border: '1px solid var(--border-subtle)',
      borderRadius: 14, display: 'block',
    }}>
      {/* Thumbnail */}
      <div style={{
        width: '100%', height: 130,
        background: 'var(--bg-overlay)',
        overflow: 'hidden', borderRadius: '14px 14px 0 0',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 32, color: 'var(--text-muted)',
      }}>
        {project.thumbnail_url
          ? <img src={project.thumbnail_url} alt={project.title}
              style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          : '◫'}
      </div>

      <div style={{ padding: '16px' }}>
        {/* Tags */}
        {tags.length > 0 && (
          <div style={{ display: 'flex', gap: 5, flexWrap: 'wrap', marginBottom: 8 }}>
            {tags.slice(0, 2).map(tag => (
              <span key={tag!.id} className="tag-pill">{tag!.name}</span>
            ))}
          </div>
        )}

        {/* Title */}
        <h3 style={{
          fontFamily: 'var(--font-cormorant), Georgia, serif',
          fontSize: 19, fontWeight: 400,
          lineHeight: 1.2, marginBottom: 10,
          color: 'var(--text-primary)',
        }}>
          {project.title}
        </h3>

        {/* Author + stars */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{
            width: 22, height: 22, borderRadius: '50%',
            background: 'var(--bg-overlay)', overflow: 'hidden',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 10, color: 'var(--accent)', flexShrink: 0,
          }}>
            {author?.avatar_url
              ? <img src={author.avatar_url}
                  style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
              : author?.username?.[0]?.toUpperCase()}
          </div>
          <span style={{
            fontSize: 12, color: 'var(--text-muted)',
            flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
          }}>
            {author?.full_name || author?.username}
          </span>
          <span style={{ fontSize: 12, color: 'var(--accent)', flexShrink: 0 }}>
            ★ {project.star_count}
          </span>
        </div>
      </div>
    </Link>
  )
}

// ─── PAGE ──────────────────────────────────────────────────────────────────
export default async function HomePage() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  // Stats counts
  const [
    { count: projectCount },
    { count: teamCount },
    { count: assignmentCount },
  ] = await Promise.all([
    supabase.from('projects').select('*', { count: 'exact', head: true }).eq('status', 'approved'),
    supabase.from('teams').select('*', { count: 'exact', head: true }),
    supabase.from('assignments').select('*', { count: 'exact', head: true }).eq('is_public', true),
  ])

  // Trending projects
  const { data: trendingRaw } = await supabase
    .from('projects')
    .select(`
      *,
      profiles!projects_submitted_by_fkey ( id, username, avatar_url, full_name ),
      project_tags ( tag_id, tags ( id, name, color ) ),
      project_members ( profile_id, role, profiles!project_members_profile_id_fkey ( id, username, avatar_url, full_name ) )
    `)
    .eq('status', 'approved')
    .order('star_count', { ascending: false })
    .limit(6)
  const trending = (trendingRaw as unknown as ProjectWithRelations[]) ?? []

  // Recent public assignments
  const { data: recentAssignmentsRaw } = await supabase
    .from('assignments')
    .select('*, profiles ( id, username, avatar_url, full_name )')
    .eq('is_public', true)
    .order('created_at', { ascending: false })
    .limit(4)
  const recentAssignments = (recentAssignmentsRaw as unknown as AssignmentWithProfile[]) ?? []

  return (
    <div style={{ padding: '56px 48px 80px', width: '100%' }}>
      <div style={{ maxWidth: 1200, margin: '0 auto' }}>

        {/* ─── HERO ─────────────────────────────────────────────────── */}
        <div className="animate-fade-up" style={{ marginBottom: 56 }}>

          {/* Greeting — client component so it reads browser timezone */}
          <Greeting hasUser={!!user} />

          <h1 style={{
            fontFamily: 'var(--font-cormorant), Georgia, serif',
            fontSize: 'clamp(64px, 9vw, 108px)',
            fontWeight: 400,
            lineHeight: 0.95,
            color: 'var(--text-primary)',
            marginBottom: 0,
          }}>
            Knowledge
          </h1>
          <h1 style={{
            fontFamily: 'var(--font-cormorant), Georgia, serif',
            fontSize: 'clamp(64px, 9vw, 108px)',
            fontWeight: 300,
            fontStyle: 'italic',
            lineHeight: 0.95,
            color: 'var(--text-secondary)',
            marginBottom: 36,
          }}>
            doesn&apos;t graduate.
          </h1>
          <p style={{
            fontSize: 16, color: 'var(--text-secondary)',
            maxWidth: 540, lineHeight: 1.8, fontWeight: 300,
          }}>
            Forge is the project-sharing and knowledge-preservation platform
            for ITM University. Submit your work permanently so future
            students can discover and build on top of it.
          </p>
        </div>

        {/* ─── ACTION CARDS ─────────────────────────────────────────── */}
        <div className="animate-fade-up delay-1" style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(3, 1fr)',
          gap: 16, marginBottom: 56,
        }}>
          <ActionCard
            href="/projects/submit" icon="＋"
            title="Submit Project"
            desc="Share your work with the university permanently"
            accent
          />
          <ActionCard
            href="/projects" icon="⌕"
            title="Browse Projects"
            desc="Discover what students before you have built"
          />
          <ActionCard
            href="/teams" icon="◎"
            title="Join a Team"
            desc="Collaborate with peers on your next big idea"
          />
        </div>

        {/* ─── STATS ────────────────────────────────────────────────── */}
        <div className="animate-fade-up delay-2" style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
          gap: 1, marginBottom: 64,
          background: 'var(--border)',
          borderRadius: 16, overflow: 'hidden',
          border: '1px solid var(--border)',
        }}>
          {[
            { num: projectCount   ?? 0, label: 'Projects Archived'  },
            { num: teamCount      ?? 0, label: 'Active Teams'        },
            { num: assignmentCount ?? 0, label: 'Public Assignments' },
            { num: '∞',                  label: 'Knowledge Preserved' },
          ].map(({ num, label }) => (
            <div key={label} style={{
              background: 'var(--bg-surface)',
              padding: '28px 20px', textAlign: 'center',
            }}>
              <div style={{
                fontFamily: 'var(--font-cormorant), Georgia, serif',
                fontSize: 52, fontWeight: 300,
                color: 'var(--text-primary)',
                lineHeight: 1, marginBottom: 8,
              }}>
                {num}
              </div>
              <div style={{
                fontSize: 11, color: 'var(--text-muted)',
                letterSpacing: '0.1em', textTransform: 'uppercase',
              }}>
                {label}
              </div>
            </div>
          ))}
        </div>

        {/* ─── TRENDING PROJECTS ────────────────────────────────────── */}
        <section className="animate-fade-up delay-3" style={{ marginBottom: 64 }}>
          <div style={{
            display: 'flex', alignItems: 'baseline',
            justifyContent: 'space-between', marginBottom: 24,
          }}>
            <h2 style={{
              fontFamily: 'var(--font-cormorant), Georgia, serif',
              fontSize: 36, fontWeight: 400,
            }}>
              Trending Projects
            </h2>
            <Link href="/projects" style={{
              fontSize: 13, color: 'var(--accent)', fontWeight: 500,
            }}>
              View all →
            </Link>
          </div>

          {trending.length > 0 ? (
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
              gap: 16,
            }}>
              {trending.map(p => <TrendingCard key={p.id} project={p} />)}
            </div>
          ) : (
            /* Empty state when no projects submitted yet */
            <div style={{
              background: 'var(--bg-surface)',
              border: '2px dashed var(--border)',
              borderRadius: 20, padding: '60px 40px',
              textAlign: 'center',
            }}>
              <div style={{ fontSize: 48, marginBottom: 16, opacity: 0.25 }}>◫</div>
              <h3 style={{
                fontFamily: 'var(--font-cormorant), Georgia, serif',
                fontSize: 26, fontWeight: 400, marginBottom: 8,
              }}>
                No projects yet — be the first
              </h3>
              <p style={{
                fontSize: 14, color: 'var(--text-muted)',
                marginBottom: 28, maxWidth: 360, margin: '0 auto 28px',
              }}>
                Submit your work and start Forge&apos;s archive for ITM University.
              </p>
              <Link href="/projects/submit" style={{
                display: 'inline-flex', alignItems: 'center', gap: 8,
                padding: '12px 28px', borderRadius: 10,
                background: 'var(--accent)', color: '#1c1917',
                fontSize: 14, fontWeight: 600,
              }}>
                Submit First Project →
              </Link>
            </div>
          )}
        </section>

        {/* ─── RECENT ASSIGNMENTS ───────────────────────────────────── */}
        {recentAssignments.length > 0 && (
          <section className="animate-fade-up delay-4">
            <div style={{
              display: 'flex', alignItems: 'baseline',
              justifyContent: 'space-between', marginBottom: 24,
            }}>
              <h2 style={{
                fontFamily: 'var(--font-cormorant), Georgia, serif',
                fontSize: 36, fontWeight: 400,
              }}>
                Recent Assignments
              </h2>
              <Link href="/assignments" style={{
                fontSize: 13, color: 'var(--accent)', fontWeight: 500,
              }}>
                View all →
              </Link>
            </div>
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))',
              gap: 12,
            }}>
              {recentAssignments.map(a => (
                <Link key={a.id} href={`/assignments/${a.id}`}
                  className="feature-card-hover" style={{
                    background: 'var(--bg-surface)',
                    border: '1px solid var(--border-subtle)',
                    borderRadius: 12, padding: '18px', display: 'block',
                  }}>
                  <div style={{
                    fontSize: 10, letterSpacing: '0.15em',
                    textTransform: 'uppercase', color: 'var(--accent)',
                    marginBottom: 8,
                  }}>
                    {a.subject} · {a.semester}
                  </div>
                  <div style={{
                    fontSize: 15, fontWeight: 500,
                    color: 'var(--text-primary)', marginBottom: 6,
                  }}>
                    {a.title}
                  </div>
                  <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>
                    by @{a.profiles?.username}
                  </div>
                </Link>
              ))}
            </div>
          </section>
        )}

      </div>
    </div>
  )
}
